sys_ui_script.script:
var x_153465_discovert = x_153465_discovert || {};
x_153465_discovert.dtech_tasker_common = (function() {
	"use strict";
	var l_constants = {};
	l_constants.TABLES = {
		"TABLE_NAME_ORGANIZATIONAL_MEMBER": "x_153465_discovert_discover_office_members",
		"TABLE_NAME_ORGANIZATIONAL_HIERARCHY": "x_153465_discovert_discover_office_hierarchy",
		"TABLE_NAME_ORGANIZATIONAL_USERS": "x_153465_discovert_organization_user",
		"TABLE_NAME_TASK":"x_153465_discovert_route_task_instance",
		"TABLE_NAME_TEMPLATE":"x_153465_discovert_discover_routing_template",
		"TABLE_NAME_TEMPLATE_TASK":"x_153465_discovert_route_tasks"
	};
	l_constants.APP_CONTEXTS={
		"HOME": "app_context_home",
		"HOME_FILTER": "app_context_home_filter",
		"ORGANIZATION": "app_context_organizational_hierarchy",
		"TASK": "app_context_task",
		"TEMPLATE": "app_context_template"
	};

	function _getContext(table){
		var context=l_constants.APP_CONTEXTS.HOME_FILTER;
		if(table == l_constants.TABLES.TABLE_NAME_ORGANIZATIONAL_HIERARCHY){
			context=l_constants.APP_CONTEXTS.ORGANIZATION;
		}
		if(table == l_constants.TABLES.TABLE_NAME_TASK){
			context=l_constants.APP_CONTEXTS.TASK;
		}
		if(table == l_constants.TABLES.TABLE_NAME_TEMPLATE){
			context=l_constants.APP_CONTEXTS.TEMPLATE;
		}
		return context;
	}


/* set your private variables and functions here. For example: 
	var privateVar = 0; 
	function private_function() {
		return ++privateVar;
	}
*/

/* Share variables between multiple UI scripts by adding them to your scope object. For example: 
	x_153465_discovert.sharedVar = 0; 

 Then access them in your scripts the same way. For example: 
	function get_shared() {
		return x_153465_discovert.sharedVar;
	}
*/

	return {
		CONSTANTS: l_constants,
		getContext: _getContext,

/* set your public API here. For example:
		incrementAndReturnPrivateVar: function() {
			return private_function();
		},
*/
		type:  "dtech_tasker_common"
	};
})();
